concept_explanation.health_indicators:
**Custom HealthIndicator — know your dependencies:**

```java
import org.springframework.boot.actuate.health.*;
import org.springframework.stereotype.Component;

// Spring Boot auto-registers: DB, diskSpace, ping
// Add your own for external dependencies:

@Component
public class PaymentGatewayHealthIndicator implements HealthIndicator {

    private final PaymentGatewayClient gatewayClient;

    PaymentGatewayHealthIndicator(PaymentGatewayClient client) {
        gatewayClient = client;
    }

    @Override
    public Health health() {
        try {
            long start = System.currentTimeMillis();
            boolean reachable = gatewayClient.ping();  // simple connectivity check
            long latency = System.currentTimeMillis() - start;

            if (reachable) {
                return Health.up()
                    .withDetail("latencyMs", latency)
                    .withDetail("endpoint", gatewayClient.getUrl())
                    .build();
            } else {
                return Health.down()
                    .withDetail("reason", "Gateway ping failed")
                    .build();
            }
        } catch (Exception e) {
            return Health.down(e)
                .withDetail("reason", e.getMessage())
                .build();
        }
    }
}

// Result in /actuator/health:
// {
//   "status": "UP",
//   "components": {
//     "paymentGateway": {"status": "UP", "details": {"latencyMs": 45, "endpoint": "https://api.razorpay.com"}},
//     "db": {"status": "UP"},
//     "diskSpace": {"status": "UP"}
//   }
// }
```

concept_explanation.micrometer_metrics:
**Micrometer — custom business metrics:**

```java
import io.micrometer.core.instrument.*;

@Service
public class OrderService {

    private final MeterRegistry registry;
    private final Counter ordersPlaced;
    private final Counter ordersFailed;
    private final AtomicInteger activeOrders;

    OrderService(MeterRegistry registry, OrderRepository repo) {
        this.registry = registry;

        // Counter: monotonically increasing count
        ordersPlaced = Counter.builder("orders.placed")
            .description("Total orders placed successfully")
            .tag("service", "payment")
            .register(registry);

        ordersFailed = Counter.builder("orders.failed")
            .description("Total orders that failed")
            .register(registry);

        // Gauge: current value (can go up or down)
        activeOrders = registry.gauge("orders.active",
            new AtomicInteger(0));
    }

    public Order placeOrder(OrderRequest req) {
        activeOrders.incrementAndGet();
        try {
            Order saved = repo.save(new Order(req));
            ordersPlaced.increment();
            return saved;
        } catch (Exception e) {
            ordersFailed.increment();
            throw e;
        } finally {
            activeOrders.decrementAndGet();
        }
    }

    // Timer: measure operation duration
    public void processWithTiming(OrderRequest req) {
        Timer.Sample sample = Timer.start(registry);
        try {
            processOrder(req);
        } finally {
            sample.stop(Timer.builder("order.processing.time")
                .description("Time to process an order")
                .tag("status", "success")
                .register(registry));
        }
    }
}
```

**Query metrics at runtime:**
```bash
# Count of placed orders:
curl /actuator/metrics/orders.placed
→ {"name":"orders.placed","measurements":[{"statistic":"COUNT","value":15234.0}]}

# Active orders (gauge):
curl /actuator/metrics/orders.active
→ {"measurements":[{"statistic":"VALUE","value":42.0}]}
```

