```java
@Service
public class PaymentService {
    private final Counter processed;
    private final Counter failed;
    private final AtomicInteger pending;
    private final Timer processingTimer;

    PaymentService(MeterRegistry registry, PaymentRepository repo) {
        processed = Counter.builder("payments.processed").register(registry);
        failed    = Counter.builder("payments.failed").register(registry);
        pending   = registry.gauge("payments.pending", new AtomicInteger(0));
        processingTimer = Timer.builder("payment.processing.duration")
            .description("Payment end-to-end processing time")
            .register(registry);
    }

    public Payment process(PaymentRequest req) {
        pending.incrementAndGet();
        return processingTimer.record(() -> {
            try {
                Payment saved = repo.save(new Payment(req));
                processed.increment();
                return saved;
            } catch (Exception e) {
                failed.increment();
                throw e;
            } finally {
                pending.decrementAndGet();
            }
        });
    }
}
```

