class ActuatorTest {
    @Autowired TestRestTemplate rest;

    @Test
    void health_returns200Up() {
        var response = rest.getForEntity("/actuator/health", String.class);
        assertEquals(HttpStatus.OK, response.getStatusCode());
        assertTrue(response.getBody().contains("\"status\":\"UP\""));
    }

    @Test
    void info_returnsAppName() {
        var response = rest.getForEntity("/actuator/info", String.class);
        assertEquals(HttpStatus.OK, response.getStatusCode());
        assertTrue(response.getBody().contains("payment-service"));
    }
}
